SELECT COUNT(signal_id)
FROM equalizations
WHERE equalization_type = 'non-linear';

SELECT COUNT(signal_id) AS measurement_count
FROM rf_signals
WHERE signal_source = 'measurement';

SELECT COUNT(*) AS successful_results_count
FROM workflow_results
WHERE result_status = 'success';

SELECT signal_id, equalization_type, equalized_raw
FROM equalizations
WHERE equalization_id = 0;

SELECT signal_source
FROM rf_signals
WHERE signal_id = 1;
